DROP TABLE IF EXISTS `Mensagens`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `Mensagens` (
  `IDMensagem` int NOT NULL AUTO_INCREMENT,
  `IDSimulacao` int NOT NULL,
  `Sala` int DEFAULT NULL,
  `Sensor` varchar(10) DEFAULT NULL,
  `Leitura` decimal(6,2) DEFAULT NULL,
  `TipoAlerta` varchar(50) NOT NULL,
  `Msg` varchar(100) DEFAULT NULL,
  `Hora` datetime DEFAULT NULL,
  `HoraEscrita` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`IDMensagem`),
  KEY `IDSimulacao` (`IDSimulacao`),
  KEY `Sala` (`Sala`),
  CONSTRAINT `Mensagens_ibfk_1` FOREIGN KEY (`IDSimulacao`) REFERENCES `Simulacao` (`IDSimulacao`),
  CONSTRAINT `Mensagens_ibfk_2` FOREIGN KEY (`Sala`) REFERENCES `Room` (`IDRoom`)
) ENGINE=InnoDB AUTO_INCREMENT=2206 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
