DROP TABLE IF EXISTS `SystemLog`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `SystemLog` (
  `IDLog` int NOT NULL AUTO_INCREMENT,
  `IDSimulacao` int DEFAULT NULL,
  `Component` varchar(20) NOT NULL COMMENT 'script1, script2, script3, trigger, php',
  `Level` enum('INFO','WARN','ERROR') NOT NULL,
  `Message` text NOT NULL,
  `CreatedAt` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`IDLog`),
  KEY `IDSimulacao` (`IDSimulacao`),
  CONSTRAINT `SystemLog_ibfk_1` FOREIGN KEY (`IDSimulacao`) REFERENCES `Simulacao` (`IDSimulacao`)
) ENGINE=InnoDB AUTO_INCREMENT=485 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
