DROP TABLE IF EXISTS `TriggerLog`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `TriggerLog` (
  `IDTrigger` int NOT NULL AUTO_INCREMENT,
  `IDSimulacao` int NOT NULL,
  `IDRoom` int NOT NULL,
  `CountOdd` int NOT NULL,
  `CountEven` int NOT NULL,
  `TriggeredAt` datetime DEFAULT CURRENT_TIMESTAMP,
  `Result` tinyint NOT NULL COMMENT '1=ponto ganho, -1=meio ponto perdido',
  PRIMARY KEY (`IDTrigger`),
  KEY `IDSimulacao` (`IDSimulacao`),
  KEY `IDRoom` (`IDRoom`),
  CONSTRAINT `TriggerLog_ibfk_1` FOREIGN KEY (`IDSimulacao`) REFERENCES `Simulacao` (`IDSimulacao`),
  CONSTRAINT `TriggerLog_ibfk_2` FOREIGN KEY (`IDRoom`) REFERENCES `Room` (`IDRoom`)
) ENGINE=InnoDB AUTO_INCREMENT=418 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
